import { compression, coalesceRequests } from "@hushkey/howl/middleware";

app.use(coalesceRequests()); // recommended first
app.use(compression());
app.use(staticFiles());
app.fsApiRoutes(config);
app.fsClientRoutes();

import { csp } from "@hushkey/howl/middleware";

app.use(csp()); // nonce on by default

// Read the active nonce from your own middleware
import { getNonce } from "@hushkey/howl";
app.use((ctx) => {
  const nonce = getNonce(ctx); // 32-char hex string per request
  return ctx.next();
});

import { trailingSlashes } from "@hushkey/howl/middleware";

app.use(trailingSlashes("never"));  // /about/ → 308 redirect to /about
app.use(trailingSlashes("always")); // /about  → 308 redirect to /about/

import type { Middleware } from "@hushkey/howl";
import type { State } from "./howl.config.ts";

const requestId: Middleware<State> = (ctx) => {
  ctx.headers.set("X-Request-Id", crypto.randomUUID());
  return ctx.next();
};

// Guard: redirect unauthenticated users
const requireAuth: Middleware<State> = (ctx) => {
  if (!ctx.state.userContext) {
    return ctx.partialRedirect("/login");
  }
  return ctx.next();
};

app.use(requestId);
app.get("/dashboard", requireAuth, (ctx) => ctx.render(<Dashboard />));

